namespace sv_b74e250a5bed4043bb442e18a1dc893b.Services;

public record Product(int Id, string Name, decimal Price, string Category, double Rating, bool InStock, string ImageUrl);
public record ProductFilter(List<string>? Categories, decimal? MinPrice, decimal? MaxPrice, bool InStockOnly);
public record PagedResult<T>(List<T> Items, int TotalCount, int Page, int PageSize);

public interface IProductService
{
    Task<PagedResult<Product>> SearchAsync(ProductFilter filter, string sortBy, int page, int pageSize);
    Task<List<string>> GetCategoriesAsync();
}

@using sv_b74e250a5bed4043bb442e18a1dc893b.Services

<div class="product-card" @onclick="OnCardClicked">
    <div class="product-image" role="img" aria-label="@Product.Name">
        <span>@Product.Name</span>
    </div>
    <div class="product-info">
        <h3 class="product-name" title="@Product.Name">@Product.Name</h3>
        <p class="product-price">@Product.Price.ToString("C")</p>
        <div class="product-rating" title="@($"{Product.Rating:F1} out of 5")">
            @GetStarDisplay(Product.Rating)
        </div>
        @if (!Product.InStock)
        {
            <span class="out-of-stock-badge">Out of Stock</span>
        }
        <button class="btn-add-to-cart"
                disabled="@(!Product.InStock)"
                @onclick="OnAddToCartClicked"
                @onclick:stopPropagation="true">
            Add to Cart
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public Product Product { get; set; } = default!;

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    [Parameter]
    public EventCallback<Product> OnAddToCart { get; set; }

    private async Task OnCardClicked()
    {
        await OnProductSelected.InvokeAsync(Product);
    }

    private async Task OnAddToCartClicked()
    {
        if (Product.InStock)
        {
            await OnAddToCart.InvokeAsync(Product);
        }
    }

    private static string GetStarDisplay(double rating)
    {
        int fullStars = (int)Math.Round(rating);
        int emptyStars = 5 - fullStars;
        return new string('★', fullStars) + new string('☆', emptyStars);
    }
}

@page "/catalog"
@using sv_b74e250a5bed4043bb442e18a1dc893b.Services
@inject IProductService ProductService
@inject NavigationManager Navigation
@rendermode InteractiveServer

<PageTitle>Product Catalog</PageTitle>

<div class="catalog-container">
    @* ── Left Sidebar ── *@
    <aside class="catalog-sidebar">
        <h2>Filters</h2>

        <section class="filter-section">
            <h3>Category</h3>
            @if (categories is not null)
            {
                @foreach (var cat in categories)
                {
                    <label class="filter-checkbox">
                        <input type="checkbox"
                               checked="@selectedCategories.Contains(cat)"
                               @onchange="e => ToggleCategory(cat, (bool)e.Value!)" />
                        @cat
                    </label>
                }
            }
            else
            {
                <p class="loading-text">Loading categories…</p>
            }
        </section>

        <section class="filter-section">
            <h3>Price Range</h3>
            <div class="price-inputs">
                <label>
                    Min
                    <input type="number" min="0" step="0.01" @bind="minPrice" placeholder="0" />
                </label>
                <label>
                    Max
                    <input type="number" min="0" step="0.01" @bind="maxPrice" placeholder="Any" />
                </label>
            </div>
        </section>

        <section class="filter-section">
            <label class="filter-checkbox">
                <input type="checkbox" @bind="inStockOnly" />
                In Stock Only
            </label>
        </section>

        <div class="filter-actions">
            <button class="btn-apply" @onclick="ApplyFilters">Apply Filters</button>
            <button class="btn-clear" @onclick="ClearFilters">Clear Filters</button>
        </div>
    </aside>

    @* ── Main Content ── *@
    <main class="catalog-main">
        @if (errorMessage is not null)
        {
            <div class="catalog-error">
                <p>⚠️ @errorMessage</p>
                <button class="btn-apply" @onclick="LoadProductsAsync">Retry</button>
            </div>
        }
        else if (isLoading)
        {
            <div class="catalog-loading">
                <p>Loading products…</p>
            </div>
        }
        else if (result is null || result.Items.Count == 0)
        {
            <div class="catalog-empty">
                <p>No products found. Try adjusting your filters.</p>
            </div>
        }
        else
        {
            @* Toolbar *@
            <div class="catalog-toolbar">
                <div class="sort-control">
                    <label for="sortSelect">Sort by:</label>
                    <select id="sortSelect" @bind="sortBy" @bind:after="LoadProductsAsync">
                        <option value="price_asc">Price: Low to High</option>
                        <option value="price_desc">Price: High to Low</option>
                        <option value="name_asc">Name: A–Z</option>
                        <option value="rating_desc">Rating: Highest</option>
                    </select>
                </div>
                <span class="results-summary">
                    Showing @FirstItem–@LastItem of @result.TotalCount products
                </span>
            </div>

            @* Product Grid *@
            <div class="product-grid">
                @foreach (var product in result.Items)
                {
                    <ProductCard Product="product"
                                 OnProductSelected="HandleProductSelected"
                                 OnAddToCart="HandleAddToCart" />
                }
            </div>

            @* Pagination *@
            <nav class="pagination" aria-label="Product page navigation">
                <button class="page-btn" disabled="@(currentPage <= 1)" @onclick="GoToPreviousPage">
                    Previous
                </button>

                @for (int i = 1; i <= TotalPages; i++)
                {
                    var pageNum = i;
                    <button class="page-btn @(pageNum == currentPage ? "active" : "")"
                            @onclick="() => GoToPage(pageNum)">
                        @pageNum
                    </button>
                }

                <button class="page-btn" disabled="@(currentPage >= TotalPages)" @onclick="GoToNextPage">
                    Next
                </button>
            </nav>
        }
    </main>
</div>

@code {
    private List<string>? categories;
    private HashSet<string> selectedCategories = new();
    private decimal? minPrice;
    private decimal? maxPrice;
    private bool inStockOnly;

    private string sortBy = "price_asc";
    private int currentPage = 1;
    private const int PageSize = 12;

    private PagedResult<Product>? result;
    private bool isLoading;
    private string? errorMessage;

    private int TotalPages => result is null || result.TotalCount == 0
        ? 1
        : (int)Math.Ceiling((double)result.TotalCount / PageSize);

    private int FirstItem => (currentPage - 1) * PageSize + 1;
    private int LastItem => Math.Min(currentPage * PageSize, result?.TotalCount ?? 0);

    protected override async Task OnInitializedAsync()
    {
        await LoadCategoriesAsync();
        await LoadProductsAsync();
    }

    private async Task LoadCategoriesAsync()
    {
        try
        {
            categories = await ProductService.GetCategoriesAsync();
        }
        catch
        {
            categories = new List<string>();
        }
    }

    private async Task LoadProductsAsync()
    {
        isLoading = true;
        errorMessage = null;
        StateHasChanged();

        try
        {
            var filter = new ProductFilter(
                Categories: selectedCategories.Count > 0 ? selectedCategories.ToList() : null,
                MinPrice: minPrice,
                MaxPrice: maxPrice,
                InStockOnly: inStockOnly
            );

            result = await ProductService.SearchAsync(filter, sortBy, currentPage, PageSize);
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load products: {ex.Message}";
            result = null;
        }
        finally
        {
            isLoading = false;
        }
    }

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked)
            selectedCategories.Add(category);
        else
            selectedCategories.Remove(category);
    }

    private async Task ApplyFilters()
    {
        currentPage = 1;
        await LoadProductsAsync();
    }

    private async Task ClearFilters()
    {
        selectedCategories.Clear();
        minPrice = null;
        maxPrice = null;
        inStockOnly = false;
        currentPage = 1;
        await LoadProductsAsync();
    }

    private async Task GoToPage(int page)
    {
        currentPage = page;
        await LoadProductsAsync();
    }

    private async Task GoToPreviousPage() => await GoToPage(currentPage - 1);
    private async Task GoToNextPage() => await GoToPage(currentPage + 1);

    private void HandleProductSelected(Product product)
    {
        Navigation.NavigateTo($"/product/{product.Id}");
    }

    private void HandleAddToCart(Product product)
    {
        // Placeholder for cart integration
    }
}

/* ── Layout ── */
.catalog-container {
    display: flex;
    gap: 1.5rem;
    max-width: 1400px;
    margin: 0 auto;
    padding: 1.5rem;
}

/* ── Sidebar ── */
.catalog-sidebar {
    flex: 0 0 25%;
    min-width: 220px;
    background: #f8f9fa;
    border-radius: 8px;
    padding: 1.25rem;
    align-self: flex-start;
    position: sticky;
    top: 1rem;
}

.catalog-sidebar h2 {
    margin: 0 0 1rem;
    font-size: 1.25rem;
}

.filter-section {
    margin-bottom: 1.25rem;
}

.filter-section h3 {
    font-size: 0.95rem;
    margin: 0 0 0.5rem;
    color: #555;
}

.filter-checkbox {
    display: flex;
    align-items: center;
    gap: 0.4rem;
    margin-bottom: 0.35rem;
    cursor: pointer;
    font-size: 0.9rem;
}

.price-inputs {
    display: flex;
    gap: 0.5rem;
}

.price-inputs label {
    display: flex;
    flex-direction: column;
    font-size: 0.85rem;
    color: #555;
    flex: 1;
}

.price-inputs input {
    margin-top: 0.2rem;
    padding: 0.4rem;
    border: 1px solid #ccc;
    border-radius: 4px;
    width: 100%;
    box-sizing: border-box;
}

.filter-actions {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
}

.btn-apply,
.btn-clear {
    padding: 0.5rem 1rem;
    border: none;
    border-radius: 6px;
    cursor: pointer;
    font-size: 0.9rem;
    font-weight: 500;
}

.btn-apply {
    background: #0d6efd;
    color: #fff;
}

.btn-apply:hover {
    background: #0b5ed7;
}

.btn-clear {
    background: #e9ecef;
    color: #333;
}

.btn-clear:hover {
    background: #dee2e6;
}

/* ── Main Content ── */
.catalog-main {
    flex: 1;
    min-width: 0;
}

.catalog-toolbar {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 1rem;
    flex-wrap: wrap;
    gap: 0.5rem;
}

.sort-control {
    display: flex;
    align-items: center;
    gap: 0.4rem;
    font-size: 0.9rem;
}

.sort-control select {
    padding: 0.35rem 0.5rem;
    border: 1px solid #ccc;
    border-radius: 4px;
}

.results-summary {
    font-size: 0.9rem;
    color: #666;
}

/* ── Product Grid ── */
.product-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(220px, 1fr));
    gap: 1.25rem;
}

/* ── States ── */
.catalog-loading,
.catalog-empty,
.catalog-error {
    text-align: center;
    padding: 3rem 1rem;
    color: #666;
}

.catalog-error {
    color: #dc3545;
}

.loading-text {
    font-size: 0.85rem;
    color: #999;
}

/* ── Pagination ── */
.pagination {
    display: flex;
    justify-content: center;
    align-items: center;
    gap: 0.35rem;
    margin-top: 1.5rem;
    flex-wrap: wrap;
}

.page-btn {
    padding: 0.4rem 0.75rem;
    border: 1px solid #dee2e6;
    border-radius: 4px;
    background: #fff;
    cursor: pointer;
    font-size: 0.9rem;
}

.page-btn:hover:not(:disabled):not(.active) {
    background: #e9ecef;
}

.page-btn.active {
    background: #0d6efd;
    color: #fff;
    border-color: #0d6efd;
}

.page-btn:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

/* ── Product Card ── */
::deep .product-card {
    border: 1px solid #e0e0e0;
    border-radius: 8px;
    overflow: hidden;
    cursor: pointer;
    transition: box-shadow 0.2s, transform 0.15s;
    display: flex;
    flex-direction: column;
    background: #fff;
}

::deep .product-card:hover {
    box-shadow: 0 4px 16px rgba(0, 0, 0, 0.1);
    transform: translateY(-2px);
}

::deep .product-image {
    background: #e9ecef;
    height: 160px;
    display: flex;
    align-items: center;
    justify-content: center;
    color: #999;
    font-size: 0.85rem;
    text-align: center;
    padding: 0.5rem;
}

::deep .product-info {
    padding: 0.75rem;
    display: flex;
    flex-direction: column;
    gap: 0.3rem;
    flex: 1;
}

::deep .product-name {
    margin: 0;
    font-size: 1rem;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

::deep .product-price {
    margin: 0;
    font-weight: 600;
    font-size: 1.05rem;
    color: #0d6efd;
}

::deep .product-rating {
    color: #f5a623;
    font-size: 1rem;
    letter-spacing: 1px;
}

::deep .out-of-stock-badge {
    display: inline-block;
    background: #dc3545;
    color: #fff;
    font-size: 0.75rem;
    padding: 0.15rem 0.5rem;
    border-radius: 4px;
    align-self: flex-start;
    font-weight: 500;
}

::deep .btn-add-to-cart {
    margin-top: auto;
    padding: 0.45rem;
    border: none;
    border-radius: 6px;
    background: #198754;
    color: #fff;
    font-size: 0.85rem;
    cursor: pointer;
    font-weight: 500;
}

::deep .btn-add-to-cart:hover:not(:disabled) {
    background: #157347;
}

::deep .btn-add-to-cart:disabled {
    background: #ccc;
    cursor: not-allowed;
}

