/* ── Layout ── */
.catalog-container {
    display: flex;
    gap: 1.5rem;
    max-width: 1400px;
    margin: 0 auto;
    padding: 1.5rem;
}

/* ── Sidebar ── */
.catalog-sidebar {
    flex: 0 0 25%;
    min-width: 220px;
    background: #f8f9fa;
    border-radius: 8px;
    padding: 1.25rem;
    align-self: flex-start;
    position: sticky;
    top: 1rem;
}

.catalog-sidebar h2 {
    margin: 0 0 1rem;
    font-size: 1.25rem;
}

.filter-section {
    margin-bottom: 1.25rem;
}

.filter-section h3 {
    font-size: 0.95rem;
    margin: 0 0 0.5rem;
    color: #555;
}

.filter-checkbox {
    display: flex;
    align-items: center;
    gap: 0.4rem;
    margin-bottom: 0.35rem;
    cursor: pointer;
    font-size: 0.9rem;
}

.price-inputs {
    display: flex;
    gap: 0.5rem;
}

.price-inputs label {
    display: flex;
    flex-direction: column;
    font-size: 0.85rem;
    color: #555;
    flex: 1;
}

.price-inputs input {
    margin-top: 0.2rem;
    padding: 0.4rem;
    border: 1px solid #ccc;
    border-radius: 4px;
    width: 100%;
    box-sizing: border-box;
}

.filter-actions {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
}

.btn-apply,
.btn-clear {
    padding: 0.5rem 1rem;
    border: none;
    border-radius: 6px;
    cursor: pointer;
    font-size: 0.9rem;
    font-weight: 500;
}

.btn-apply {
    background: #0d6efd;
    color: #fff;
}

.btn-apply:hover {
    background: #0b5ed7;
}

.btn-clear {
    background: #e9ecef;
    color: #333;
}

.btn-clear:hover {
    background: #dee2e6;
}

/* ── Main Content ── */
.catalog-main {
    flex: 1;
    min-width: 0;
}

.catalog-toolbar {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 1rem;
    flex-wrap: wrap;
    gap: 0.5rem;
}

.sort-control {
    display: flex;
    align-items: center;
    gap: 0.4rem;
    font-size: 0.9rem;
}

.sort-control select {
    padding: 0.35rem 0.5rem;
    border: 1px solid #ccc;
    border-radius: 4px;
}

.results-summary {
    font-size: 0.9rem;
    color: #666;
}

/* ── Product Grid ── */
.product-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(220px, 1fr));
    gap: 1.25rem;
}

/* ── States ── */
.catalog-loading,
.catalog-empty,
.catalog-error {
    text-align: center;
    padding: 3rem 1rem;
    color: #666;
}

.catalog-error {
    color: #dc3545;
}

.loading-text {
    font-size: 0.85rem;
    color: #999;
}

/* ── Pagination ── */
.pagination {
    display: flex;
    justify-content: center;
    align-items: center;
    gap: 0.35rem;
    margin-top: 1.5rem;
    flex-wrap: wrap;
}

.page-btn {
    padding: 0.4rem 0.75rem;
    border: 1px solid #dee2e6;
    border-radius: 4px;
    background: #fff;
    cursor: pointer;
    font-size: 0.9rem;
}

.page-btn:hover:not(:disabled):not(.active) {
    background: #e9ecef;
}

.page-btn.active {
    background: #0d6efd;
