+@page "/catalog"
+@using sv_b74e250a5bed4043bb442e18a1dc893b.Services
+@inject IProductService ProductService
+@inject NavigationManager Navigation
+@rendermode InteractiveServer
+
+<PageTitle>Product Catalog</PageTitle>
+
+<div class="catalog-container">
+    @* ── Left Sidebar ── *@
+    <aside class="catalog-sidebar">
+        <h2>Filters</h2>
+
+        <section class="filter-section">
+            <h3>Category</h3>
+            @if (categories is not null)
+            {
+                @foreach (var cat in categories)
+                {
+                    <label class="filter-checkbox">
+                        <input type="checkbox"
+                               checked="@selectedCategories.Contains(cat)"
+                               @onchange="e => ToggleCategory(cat, (bool)e.Value!)" />
+                        @cat
+                    </label>
+                }
+            }
+            else
+            {
+                <p class="loading-text">Loading categories…</p>
+            }
+        </section>
+
+        <section class="filter-section">
+            <h3>Price Range</h3>
+            <div class="price-inputs">
+                <label>
+                    Min
+                    <input type="number" min="0" step="0.01" @bind="minPrice" placeholder="0" />
+                </label>
+                <label>
+                    Max
+                    <input type="number" min="0" step="0.01" @bind="maxPrice" placeholder="Any" />
+                </label>
+            </div>
+        </section>
+
+        <section class="filter-section">
+            <label class="filter-checkbox">
+                <input type="checkbox" @bind="inStockOnly" />
+                In Stock Only
+            </label>
+        </section>
+
+        <div class="filter-actions">
+            <button class="btn-apply" @onclick="ApplyFilters">Apply Filters</button>
+            <button class="btn-clear" @onclick="ClearFilters">Clear Filters</button>
+        </div>
+    </aside>
+
+    @* ── Main Content ── *@
+    <main class="catalog-main">
+        @if (errorMessage is not null)
+        {
+            <div class="catalog-error">
+                <p>⚠️ @errorMessage</p>
+                <button class="btn-apply" @onclick="LoadProductsAsync">Retry</button>
+            </div>
+        }
+        else if (isLoading)
+        {
+            <div class="catalog-loading">
+                <p>Loading products…</p>
+            </div>
+        }
+        else if (result is null || result.Items.Count == 0)
+        {
+            <div class="catalog-empty">
+                <p>No products found. Try adjusting your filters.</p>
+            </div>
+        }
+        else
+        {
+            @* Toolbar *@
+            <div class="catalog-toolbar">
+                <div class="sort-control">
+                    <label for="sortSelect">Sort by:</label>
+                    <select id="sortSelect" @bind="sortBy" @bind:after="LoadProductsAsync">
+                        <option value="price_asc">Price: Low to High</option>
+                        <option value="price_desc">Price: High to Low</option>
+                        <option value="name_asc">Name: A–Z</option>
+                        <option value="rating_desc">Rating: Highest</option>
+                    </select>
+                </div>
+                <span class="results-summary">
+                    Showing @FirstItem–@LastItem of @result.TotalCount products
+                </span>
+            </div>
+
+            @* Product Grid *@
+            <div class="product-grid">
+                @foreach (var product in result.Items)
+                {
+                    <ProductCard Product="product"
+                                 OnProductSelected="HandleProductSelected"
+                                 OnAddToCart="HandleAddToCart" />
+                }
+            </div>
+
+            @* Pagination *@
+            <nav class="pagination" aria-label="Product page navigation">
+                <button class="page-btn" disabled="@(currentPage <= 1)" @onclick="GoToPreviousPage">
+                    Previous
+                </button>
+
+                @for (int i = 1; i <= TotalPages; i++)
+                {
+                    var pageNum = i;
+                    <button class="page-btn @(pageNum == currentPage ? "active" : "")"
+                            @onclick="() => GoToPage(pageNum)">
+                        @pageNum
+                    </button>
+                }
+
+                <button class="page-btn" disabled="@(currentPage >= TotalPages)" @onclick="GoToNextPage">
+                    Next
+                </button>
+            </nav>
+        }
+    </main>
+</div>
+
+@code {
+    private List<string>? categories;
+    private HashSet<string> selectedCategories = new();
+    private decimal? minPrice;
+    private decimal? maxPrice;
+    private bool inStockOnly;
+
+    private string sortBy = "price_asc";
+    private int currentPage = 1;
+    private const int PageSize = 12;
+
+    private PagedResult<Product>? result;
+    private bool isLoading;
+    private string? errorMessage;
+
+    private int TotalPages => result is null || result.TotalCount == 0
+        ? 1
+        : (int)Math.Ceiling((double)result.TotalCount / PageSize);
+
+    private int FirstItem => (currentPage - 1) * PageSize + 1;
+    private int LastItem => Math.Min(currentPage * PageSize, result?.TotalCount ?? 0);
+
+    protected override async Task OnInitializedAsync()
+    {
+        await LoadCategoriesAsync();
+        await LoadProductsAsync();
+    }
+
+    private async Task LoadCategoriesAsync()
+    {
+        try
+        {
+            categories = await ProductService.GetCategoriesAsync();
+        }
+        catch
+        {
+            categories = new List<string>();
+        }
+    }
+
+    private async Task LoadProductsAsync()
+    {
+        isLoading = true;
+        errorMessage = null;
+        StateHasChanged();
+
+        try
+        {
+            var filter = new ProductFilter(
+                Categories: selectedCategories.Count > 0 ? selectedCategories.ToList() : null,
+                MinPrice: minPrice,
+                MaxPrice: maxPrice,
+                InStockOnly: inStockOnly
+            );
+
+            result = await ProductService.SearchAsync(filter, sortBy, currentPage, PageSize);
+        }
+        catch (Exception ex)
+        {
+            errorMessage = $"Failed to load products: {ex.Message}";
+            result = null;
+        }
+        finally
+        {
+            isLoading = false;
+        }
+    }
+
+    private void ToggleCategory(string category, bool isChecked)
+    {
+        if (isChecked)
+            selectedCategories.Add(category);
+        else
+            selectedCategories.Remove(category);
+    }
+
+    private async Task ApplyFilters()
+    {
+        currentPage = 1;
+        await LoadProductsAsync();
+    }
+
+    private async Task ClearFilters()
+    {
+        selectedCategories.Clear();
+        minPrice = null;
+        maxPrice = null;
+        inStockOnly = false;
+        currentPage = 1;
+        await LoadProductsAsync();
+    }
+
+    private async Task GoToPage(int page)
+    {
+        currentPage = page;
+        await LoadProductsAsync();
+    }
+
+    private async Task GoToPreviousPage() => await GoToPage(currentPage - 1);
+    private async Task GoToNextPage() => await GoToPage(currentPage + 1);
+
+    private void HandleProductSelected(Product product)
+    {
+        Navigation.NavigateTo($"/product/{product.Id}");
+    }
+
+    private void HandleAddToCart(Product product)
+    {
+        // Placeholder for cart integration
+    }
+}
