+.catalog-main {
+    flex: 1;
+    min-width: 0;
+}
+
+.catalog-toolbar {
+    display: flex;
+    justify-content: space-between;
+    align-items: center;
+    margin-bottom: 1rem;
+    flex-wrap: wrap;
+    gap: 0.5rem;
+}
+
+.sort-control {
+    display: flex;
+    align-items: center;
+    gap: 0.4rem;
+    font-size: 0.9rem;
+}
+
+.sort-control select {
+    padding: 0.35rem 0.5rem;
+    border: 1px solid #ccc;
+    border-radius: 4px;
+}
+
+.results-summary {
+    font-size: 0.9rem;
+    color: #666;
+}
+
+/* ── Product Grid ── */
+.product-grid {
+    display: grid;
+    grid-template-columns: repeat(auto-fill, minmax(220px, 1fr));
+    gap: 1.25rem;
+}
+
+/* ── States ── */
+.catalog-loading,
+.catalog-empty,
+.catalog-error {
+    text-align: center;
+    padding: 3rem 1rem;
+    color: #666;
+}
+
+.catalog-error {
+    color: #dc3545;
+}
+
+.loading-text {
+    font-size: 0.85rem;
+    color: #999;
+}
+
+/* ── Pagination ── */
+.pagination {
+    display: flex;
+    justify-content: center;
+    align-items: center;
+    gap: 0.35rem;
+    margin-top: 1.5rem;
+    flex-wrap: wrap;
+}
+
+.page-btn {
+    padding: 0.4rem 0.75rem;
+    border: 1px solid #dee2e6;
+    border-radius: 4px;
+    background: #fff;
+    cursor: pointer;
+    font-size: 0.9rem;
+}
+
+.page-btn:hover:not(:disabled):not(.active) {
+    background: #e9ecef;
+}
+
+.page-btn.active {
+    background: #0d6efd;
+    color: #fff;
+    border-color: #0d6efd;
+}
+
+.page-btn:disabled {
+    opacity: 0.5;
+    cursor: not-allowed;
+}
+
+/* ── Product Card ── */
+::deep .product-card {
+    border: 1px solid #e0e0e0;
+    border-radius: 8px;
+    overflow: hidden;
+    cursor: pointer;
+    transition: box-shadow 0.2s, transform 0.15s;
+    display: flex;
+    flex-direction: column;
+    background: #fff;
+}
+
+::deep .product-card:hover {
+    box-shadow: 0 4px 16px rgba(0, 0, 0, 0.1);
+    transform: translateY(-2px);
+}
+
+::deep .product-image {
+    background: #e9ecef;
+    height: 160px;
+    display: flex;
+    align-items: center;
+    justify-content: center;
+    color: #999;
+    font-size: 0.85rem;
+    text-align: center;
+    padding: 0.5rem;
+}
+
+::deep .product-info {
+    padding: 0.75rem;
+    display: flex;
+    flex-direction: column;
+    gap: 0.3rem;
+    flex: 1;
+}
+
+::deep .product-name {
+    margin: 0;
+    font-size: 1rem;
+    white-space: nowrap;
+    overflow: hidden;
+    text-overflow: ellipsis;
+}
+
+::deep .product-price {
+    margin: 0;
+    font-weight: 600;
+    font-size: 1.05rem;
+    color: #0d6efd;
+}
+
+::deep .product-rating {
+    color: #f5a623;
+    font-size: 1rem;
+    letter-spacing: 1px;
+}
+
+::deep .out-of-stock-badge {
+    display: inline-block;
+    background: #dc3545;
+    color: #fff;
+    font-size: 0.75rem;
+    padding: 0.15rem 0.5rem;
+    border-radius: 4px;
+    align-self: flex-start;
+    font-weight: 500;
+}
+
+::deep .btn-add-to-cart {
+    margin-top: auto;
+    padding: 0.45rem;
+    border: none;
+    border-radius: 6px;
+    background: #198754;
+    color: #fff;
+    font-size: 0.85rem;
+    cursor: pointer;
+    font-weight: 500;
+}
+
+::deep .btn-add-to-cart:hover:not(:disabled) {
+    background: #157347;
+}
+
+::deep .btn-add-to-cart:disabled {
+    background: #ccc;
+    cursor: not-allowed;
+}
+
